import React, { useState } from 'react';
import Drawer from '@material-ui/core/Drawer';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import IconButton from '@material-ui/core/IconButton';
import MenuIcon from '@material-ui/icons/Menu';
import { Link } from 'react-router-dom';
import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  mainMenuText: {
    fontSize: '1.2rem', // Adjust the font size for mainMenu
    // Add other mainMenu styles here
  },
  subMenuText: {
    fontSize: '1rem', // Adjust the font size for subMenu
    // Add other subMenu styles here
  },
}));

const DrawerMenu = ({ categories }) => {
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const classes = useStyles();

  const handleDrawerOpen = () => {
    setIsDrawerOpen(true);
  };

  const handleDrawerClose = () => {
    setIsDrawerOpen(false);
  };

  const generateMenuItems = () => {
    if (!Array.isArray(categories) || categories.length === 0) {
      return null;
    }

    return (
      <List>
        {categories.map((category) => {
          const { _id, mainMenu, subMenu } = category;

          if (!_id || !mainMenu) {
            return null;
          }

          return (
            <div key={_id}>
              <ListItem button component={Link} to={`/${mainMenu}`} onClick={handleDrawerClose}>
                <ListItemText
                  primary={mainMenu}
                  className={classes.mainMenuText} // Apply the mainMenu class
                />
              </ListItem>
              {Array.isArray(subMenu) && subMenu.length > 0 && (
                <List component="div" disablePadding>
                  {subMenu.map((subItem) => {
                    if (!subItem) {
                      return null;
                    }

                    const subItemId = subItem._id || ''; // handle null or undefined _id
                    const subItemText = subItem || '';

                    return (
                      <ListItem
                        key={subItemId}
                        button
                        component={Link}
                        to={`/${mainMenu}/${subItemId}`}
                        style={{ paddingLeft: 16 }}
                        onClick={handleDrawerClose}
                      >
                        <ListItemText
                          primary={subItemText}
                          className={classes.subMenuText} // Apply the subMenu class
                        />
                      </ListItem>
                    );
                  })}
                </List>
              )}
            </div>
          );
        })}
      </List>
    );
  };

  return (
    <div>
      <IconButton
        edge="start"
        color="inherit"
        aria-label="menu"
        onClick={handleDrawerOpen}
      >
        <MenuIcon />
      </IconButton>
      <Drawer anchor="top" open={isDrawerOpen} onClose={handleDrawerClose}>
        {generateMenuItems()}
      </Drawer>
    </div>
  );
};

export default DrawerMenu;
